from __future__ import annotations


def _spot(
    id_: str,
    name: str,
    address: str,
    postal_code: str,
    neighborhood: str,
    latitude: float,
    longitude: float,
    stars: float,
    review_count: int,
    categories: str,
    price_range: int,
    good_for_groups: bool = True,
    table_service: bool = True,
    takeout: bool = True,
    delivery: bool = True,
    ambiance_labels: list[str] | None = None,
) -> dict:
    return {
        "id": id_,
        "name": name,
        "address": address,
        "city": "San Francisco",
        "state": "CA",
        "postal_code": postal_code,
        "neighborhood": neighborhood,
        "latitude": latitude,
        "longitude": longitude,
        "stars": stars,
        "review_count": review_count,
        "categories": categories,
        "price_range": price_range,
        "good_for_groups": good_for_groups,
        "table_service": table_service,
        "takeout": takeout,
        "delivery": delivery,
        "ambiance_labels": ambiance_labels or ["casual"],
        "attributes": {"RestaurantsPriceRange2": str(price_range)},
    }


